import { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Screens.css";

function WelcomeScreen() {
    const [nickname, setNickname] = useState("");
    const navigate = useNavigate();

    const handleStart = () => {
        if (nickname.trim()) {
            // Only proceed if nickname is not empty
            navigate("/second", { state: { nickname } });
        } else {
            alert("Please enter a nickname!");
        }
    };

    const [selectedFile, setSelectedFile] = useState(null);

    const handleFileChange = (event) => {
        const file = event.target.files[0];
        if (file && file.name.endsWith('.cpp')) {
            setSelectedFile(file);
        } else {
            alert('Please select a .cpp file');
            event.target.value = ''; // Reset input
        }
    };

    return (
        <div>
            <h1> code the game yourself & play </h1>
            <div>
                <label htmlFor="nickname" style={{ marginRight: "10px", fontFamily: "monospace" }}>name:</label>
                <input
                    id="nickname"
                    type="text"
                    // placeholder="enter your nickname"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                />
            </div>
            <div style={{
                // display: "flex",
                alignItems: "center",
                marginTop: "10px"  // Space between the two inputs
            }}>
                <label htmlFor="file" style={{ marginRight: "10px" }}>upload your code:</label>
                <input
                    type="file"
                    id="file"
                    accept=".cpp"
                    onChange={handleFileChange}
                    style={{ display: 'none' }}  // Hide the default file input
                />
                <button
                    onClick={() => document.getElementById('file').click()}
                    style={{
                        padding: "5px 10px",
                        fontFamily: "monospace",
                        cursor: "pointer"
                    }}
                >
                    Choose File
                </button>
                {selectedFile && (
                    <span style={{
                        marginLeft: "10px",
                        fontFamily: "monospace"
                    }}>
                        {selectedFile.name}
                    </span>
                )}
            </div>
            <button onClick={handleStart} style={{ padding: "5px 10px", fontFamily: "monospace", marginTop: "100px" }}>start</button>
        </div>
    );
}

export default WelcomeScreen;
